def span_vecs(indices):
    # span over F2 excluding zero as projective flat points
    vecs=[points[i] for i in indices]
    sp={(0,0,0)}
    for v in vecs:
        sp |= {add(x,v) for x in list(sp)}
    return frozenset(vec_to_idx[v] for v in sp if v!=(0,0,0))
def r_fano(S):
    # dimension of span
    sp=span_vecs(S)
    # rank is log2(|span incl zero|)
    # compute Gaussian rank
    mat=[list(points[i]) for i in S]
    rank=0; rows=[row[:] for row in mat]; col=0
    for col in range(3):
        pivot=None
        for rr in range(rank,len(rows)):
            if rows[rr][col]:
                pivot=rr; break
        if pivot is not None:
            rows[rank],rows[pivot]=rows[pivot],rows[rank]
            for rr in range(len(rows)):
                if rr!=rank and rows[rr][col]:
                    rows[rr]=[a^b for a,b in zip(rows[rr],rows[rank])]
            rank+=1
    return rank
